import { PrismaClient, AdviceCategory, ContentSource } from '@prisma/client';
const prisma = new PrismaClient();

export async function seedInfantAdviceCards() {
  console.log('Seeding infant advice cards (months 1-12)...');
  const cards = [
    { stageKey: 'born_month_1', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 92, title: 'Cluster Feeding: What It Is and Why It Happens', summary: 'Your newborn wants to nurse constantly in the evening. This is normal cluster feeding, not a sign of low supply.', content: 'Cluster feeding is when your baby feeds very frequently, often every 30 to 60 minutes, typically during evening hours. It usually peaks around 2 to 3 weeks of age and coincides with growth spurts. This behavior helps establish your milk supply and comforts your newborn through the fussy evening period. Settle in with water, snacks, and a show you have been wanting to watch. It will pass, usually within a few days to a week.', source: 'DEVELOPMENT' as ContentSource, tags: ['cluster feeding', 'newborn', 'breastfeeding', 'growth spurt'] },
    { stageKey: 'born_month_1', category: 'SLEEP' as AdviceCategory, priority: 90, title: 'Newborn Day-Night Confusion', summary: 'Your baby sleeps all day and parties all night. Understanding and gently reversing day-night confusion.', content: 'Newborns have no circadian rhythm yet; melatonin production does not begin in earnest for several weeks. To gently guide your baby toward daytime wakefulness: expose them to natural daylight during feeds and awake periods, keep nighttime feeds quiet and dimly lit, and avoid stimulating interaction between 10 PM and 6 AM. Most babies begin sorting out day and night by 6 to 8 weeks, though full circadian regulation takes months.', source: 'DEVELOPMENT' as ContentSource, tags: ['day-night confusion', 'newborn sleep', 'circadian rhythm', 'sleep tips'] },
    { stageKey: 'born_month_1', category: 'DEVELOPMENT' as AdviceCategory, priority: 85, title: 'The First Intentional Sounds Beyond Crying', summary: 'Your newborn is already communicating. Learn to recognize the subtle sounds that come before cooing.', content: 'Around 3 to 4 weeks, your baby begins producing small throaty sounds and quiet vowel-like noises beyond reflexive crying. These are the earliest precursors to speech. You can encourage this development by responding warmly to any non-cry vocalization, leaving pauses in your own speech as if having a conversation, and making eye contact from 8 to 12 inches away. These tiny sounds are fleeting but mark the very beginning of your child\'s expressive language journey.', source: 'DEVELOPMENT' as ContentSource, tags: ['early communication', 'newborn sounds', 'vocalization', 'language development'] },
    { stageKey: 'born_month_1', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 82, title: 'Tummy Time Without Tears', summary: 'Many newborns protest tummy time. Gentle strategies to build tolerance and prevent flat spots.', content: 'Start with just 30 to 60 seconds of tummy time on your chest while you recline, which counts and feels safer to your baby. Gradually work up to floor-based tummy time on a firm surface, aiming for a total of 15 to 20 minutes spread across the day by the end of the first month. Use a rolled towel under the armpits for extra support, place a mirror or your face at eye level, and always supervise. If your baby falls asleep on their tummy during supervised play, gently roll them to their back for safe sleep.', source: 'DEVELOPMENT' as ContentSource, tags: ['tummy time', 'newborn', 'motor development', 'flat head prevention'] },
    { stageKey: 'born_month_1', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 93, title: 'Newborn Weight Gain: What to Expect', summary: 'Understanding typical weight loss and regain patterns in the first two weeks, and when to seek help.', content: 'It is normal for a breastfed newborn to lose up to 7 percent of their birth weight in the first 5 days. Weight loss of 7-10 percent warrants evaluation of breastfeeding and possible supplementation — call your pediatrician. Most babies should regain their birth weight by day 10 to 14. Adequate wet diapers are your best at-home indicator: expect 1 wet diaper on day 1, 2 on day 2, and 6 or more by day 5 and beyond. If you see fewer wet diapers, brick-dust colored urine, or if your baby seems too sleepy to feed, call your pediatrician promptly.', source: 'CLINICAL' as ContentSource, tags: ['newborn weight', 'feeding', 'wet diapers', 'growth', 'newborn health'] },
    { stageKey: 'born_month_1', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 88, title: 'Postpartum Recovery: The First Six Weeks', summary: 'Your body needs time to heal. What is normal in postpartum recovery and what warrants a call to your provider.', content: 'Vaginal bleeding can persist for up to 6 weeks, gradually changing from bright red to pink to a brownish discharge. Perineal soreness, afterpains during breastfeeding, and night sweats are all normal as your body sheds excess fluid and your uterus contracts. Prioritize rest even when you feel restless; overdoing it can prolong bleeding. Contact your provider if you soak through more than a pad per hour, pass clots larger than a golf ball, or experience signs of infection such as fever or foul-smelling discharge.', source: 'CLINICAL' as ContentSource, tags: ['postpartum recovery', 'healing', 'maternal health', 'newborn phase'] },
    { stageKey: 'born_month_1', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 91, title: 'Umbilical Cord Stump and Circumcision Care', summary: 'Proper care of the umbilical cord stump and circumcision site prevents infection and promotes healing in the first weeks.', content: 'The umbilical cord stump typically falls off between 1 and 3 weeks. Keep it clean and dry by folding the diaper down below the stump and giving sponge baths until it detaches. A small amount of dried blood or slight odor is normal; redness spreading outward, pus, or foul odor warrant a call to your pediatrician. For circumcision care, gently apply petroleum jelly to the tip of the penis with each diaper change to prevent the healing skin from sticking to the diaper. Healing is usually complete by 7 to 10 days.', source: 'CLINICAL' as ContentSource, tags: ['umbilical cord', 'circumcision care', 'newborn hygiene', 'infection prevention', '1 month'] },
    { stageKey: 'born_month_1', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 89, title: 'The Baby Blues vs. Postpartum Depression: Knowing the Difference', summary: 'Up to 80% of new mothers experience the baby blues. Understanding what is typical and what signals a need for help.', content: 'The baby blues typically onset 2 to 5 days postpartum, peak around day 4 or 5, and resolve by 2 weeks. Symptoms include mood swings, tearfulness, irritability, and feeling overwhelmed, all of which come and go. The key distinction from postpartum depression is duration: blues that persist beyond 2 weeks, worsen rather than improve, or include feelings of hopelessness, detachment from the baby, or thoughts of harming yourself or the baby are not typical and require immediate discussion with your provider. If you are not sure which you are experiencing, err on the side of reaching out.', source: 'CLINICAL' as ContentSource, tags: ['baby blues', 'postpartum depression', 'maternal mental health', 'screening', '1 month'] },
    { stageKey: 'born_month_2', category: 'DEVELOPMENT' as AdviceCategory, priority: 88, title: 'The Social Smile: More Than Just Gas', summary: 'Around 6 to 8 weeks, your baby flashes their first real social smile. What it means and how to encourage more.', content: 'The social smile is a genuine response to human faces and voices, not just a reflex. It marks an important leap in social development and helps cement the parent-child bond. To encourage more smiles: hold your face about 8 to 12 inches away, use an exaggerated happy expression, and speak in a higher-pitched, sing-song voice. Do not worry if your baby smiles at strangers the same way; discriminating between familiar and unfamiliar faces develops later, around 5 to 7 months.', source: 'DEVELOPMENT' as ContentSource, tags: ['social smile', 'development', 'bonding', '2 months'] },
    { stageKey: 'born_month_2', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 91, title: 'The 2-Month Vaccines: Preparation and Comfort', summary: 'What to expect at the first big vaccine appointment and how to soothe your baby afterward.', content: 'The 2-month visit typically includes the first doses of DTaP, PCV, Hib, IPV, rotavirus, and the second dose of Hepatitis B vaccines. Your baby may be fussy for 24 to 48 hours, run a low-grade fever, and be sleepier than usual. Have infant acetaminophen on hand but do not give it before the appointment unless your pediatrician advises it; some evidence suggests pre-dosing may reduce immune response. Comfort measures afterward: extra nursing or feeding, skin-to-skin contact, a warm bath if the injection sites are tender, and letting your baby sleep as much as they want.', source: 'CLINICAL' as ContentSource, tags: ['vaccines', '2-month shots', 'immunization', 'baby health'] },
    { stageKey: 'born_month_2', category: 'SLEEP' as AdviceCategory, priority: 86, title: 'The Witching Hour: Evening Fussiness Peaks', summary: 'If your baby cries inconsolably each evening around the same time, you are in the witching hour zone.', content: 'The witching hour typically peaks between 6 and 8 weeks and usually resolves by 12 to 14 weeks. Its exact cause is not fully understood, but theories include sensory overload, digestive discomfort, and the natural dip in milk supply that occurs in the evening for breastfeeding parents. Coping strategies: wear your baby in a carrier, step outside for fresh air, use white noise, and try the five S\'s: swaddle, side or stomach position while held, shush, swing, and suck. If you feel overwhelmed, put your baby down in a safe sleep space and step away for 5 minutes.', source: 'DEVELOPMENT' as ContentSource, tags: ['witching hour', 'evening fussiness', 'colic', 'newborn crying', '2 months'] },
    { stageKey: 'born_month_2', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 80, title: 'High-Contrast Cards and Visual Tracking', summary: 'Your baby sees the world differently. Use high-contrast images to support visual development.', content: 'At 2 months, your baby can see about 8 to 12 inches clearly and is drawn to high-contrast patterns, especially black and white and bold geometric shapes. Slowly move a high-contrast card across their field of vision to practice visual tracking, a foundational skill for later reading. You can make your own cards with a black marker on white index cards or use commercially available sets. Keep sessions brief, about 2 to 5 minutes, and stop when your baby looks away to avoid overstimulation.', source: 'DEVELOPMENT' as ContentSource, tags: ['visual development', 'high-contrast', 'newborn play', 'tracking'] },
    { stageKey: 'born_month_2', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 87, title: 'Planning Your Return to Work', summary: 'Whether your leave ends in weeks or months, early planning around feeding, childcare, and emotions helps.', content: 'If you are returning to work after parental leave, start by clarifying your feeding plan: if breastfeeding, introduce a bottle by 3 to 4 weeks if you have not already, and begin building a small freezer stash a few weeks before your return. Research your childcare options early; many quality providers have waitlists. Practice your morning routine once or twice before the actual return day to identify logistical gaps. Emotionally, it is normal to feel a mix of anticipation and grief; your bond with your baby is not broken by time apart.', source: 'DEVELOPMENT' as ContentSource, tags: ['returning to work', 'parental leave', 'childcare', 'working parent'] },
    { stageKey: 'born_month_2', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 86, title: 'Formula Preparation: Safety Essentials', summary: 'Whether you are exclusively formula feeding or supplementing, proper preparation protects your baby from serious illness.', content: 'Powdered infant formula is not sterile and can contain Cronobacter bacteria, which is rare but potentially fatal for newborns. For infants under 3 months, those born prematurely, or those with compromised immune systems, the CDC recommends using liquid concentrate or ready-to-feed formula, or preparing powdered formula with water heated to at least 158 degrees Fahrenheit and then cooled to body temperature before feeding. Always measure water first, then add powder using the scoop provided and leveling it. Never dilute formula to make it last longer; this can cause water intoxication and failure to thrive.', source: 'CLINICAL' as ContentSource, tags: ['formula preparation', 'infant formula safety', 'Cronobacter', 'feeding', '2 months'] },
    { stageKey: 'born_month_2', category: 'DEVELOPMENT' as AdviceCategory, priority: 84, title: 'Cooing: The Beautiful Soundtrack of Month Two', summary: 'Your baby\'s first vowel sounds are early language in action. What cooing tells you and how to keep the conversation going.', content: 'Cooing, or the production of soft vowel sounds like "ooo" and "ahh," typically emerges between 6 and 8 weeks and is a direct precursor to babbling and speech. It reflects your baby\'s growing control over their vocal cords and their desire to engage socially. When your baby coos, respond as if in a real conversation: make eye contact, smile, and mimic the sound back, then pause to give them a turn. This serve-and-return interaction literally builds the neural architecture for language. Record a few seconds of these early sounds; you will treasure them later.', source: 'DEVELOPMENT' as ContentSource, tags: ['cooing', 'vocalization', 'language development', 'serve and return', '2 months'] },
    { stageKey: 'born_month_2', category: 'SLEEP' as AdviceCategory, priority: 87, title: 'Safe Sleep Beyond the Newborn Phase', summary: 'Revisiting the ABCs of safe sleep after the first weeks: alone, on their back, in a crib or bassinet.', content: 'Even though your baby is no longer a fragile newborn, safe sleep practices remain critical through the first year. Place your baby on their back for every sleep, including naps, on a firm mattress with a fitted sheet only. Keep the crib empty: no bumpers, blankets, pillows, or stuffed animals. Room-sharing without bed-sharing is recommended for at least the first 6 months and ideally through the first year. If you have been co-sleeping and want to transition to a separate sleep surface, start with naps in the crib and a consistent bedtime routine in your baby\'s own sleep space.', source: 'CLINICAL' as ContentSource, tags: ['safe sleep', 'SIDS prevention', 'crib safety', 'sleep environment', '2 months'] },
    { stageKey: 'born_month_2', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 90, title: 'Postpartum Depression Screening: What to Know at 2 Months', summary: 'Screening for postpartum depression happens around 6 weeks. Understanding the screening, the symptoms, and what to do next.', content: 'The Edinburgh Postnatal Depression Scale or a similar screen is typically administered at the 6-week or 2-month visit. It is a simple, private questionnaire that asks about your mood, anxiety, and thoughts over the past week. Answer honestly; there are no wrong answers, and a positive screen is not a failure. Symptoms of postpartum depression include persistent sadness, loss of interest in activities, difficulty bonding with your baby, and sleep disturbance beyond what is expected with a newborn. Treatment options include therapy, support groups, and medication, many of which are compatible with breastfeeding. Seeking help is an act of love for both you and your baby.', source: 'CLINICAL' as ContentSource, tags: ['postpartum depression', 'PPD', 'mental health screening', 'maternal health', '2 months'] },
    { stageKey: 'born_month_3', category: 'DEVELOPMENT' as AdviceCategory, priority: 84, title: 'Discovering Hands: The Birth of Body Awareness', summary: 'Your baby has found their hands and cannot stop staring. This is the exciting beginning of self-discovery.', content: 'Around 10 to 12 weeks, babies enter a phase called hand regard, spending long moments gazing at their own hands as they move them through their visual field. This is the earliest form of body awareness and the foundation for hand-eye coordination. You will soon see your baby bring their hands together at midline and begin batting at objects. Encourage this by placing lightweight rattles or crinkle toys within reach and celebrating when contact is made. Hand discovery also leads to hand-to-mouth exploration, which is developmentally appropriate and not a sign of hunger.', source: 'DEVELOPMENT' as ContentSource, tags: ['hand regard', 'body awareness', 'hand-eye coordination', 'development', '3 months'] },
    { stageKey: 'born_month_3', category: 'SLEEP' as AdviceCategory, priority: 87, title: 'The 3-Month Sleep Shift: Reality vs. Hype', summary: 'Many parents hear about a 3-month sleep regression. Understanding what actually changes in sleep around this age.', content: 'The 3-month mark is less a regression than a maturation point where sleep cycles begin to look more like adult sleep, with lighter and deeper phases. Your baby may start waking more between cycles because they are simply more aware of their surroundings. This is also when the Moro reflex fades, and many babies outgrow the swaddle around this time. To navigate the shift: establish a consistent bedtime routine if you have not already, put your baby down drowsy but awake to build self-soothing skills, and be patient; this reorganization phase typically lasts 2 to 3 weeks.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep maturation', '3 months', 'sleep cycles', 'swaddle transition'] },
    { stageKey: 'born_month_3', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 88, title: 'Recognizing Hunger and Fullness Cues Before Crying', summary: 'By 3 months, you can learn your baby\'s early feeding signals, reducing the need for crying-based communication.', content: 'Early hunger cues include rooting with head turning, tongue thrusting, lip smacking, and sucking on hands. Crying is a late hunger cue, and a frantic baby is harder to feed calmly. Fullness cues include turning away from the breast or bottle, pushing the nipple out, relaxing hands from a fist to open palms, and falling asleep contentedly at the breast. At this age, your baby may also begin to space feeds further apart, going 3 to 4 hours between daytime feeds. Trust your baby\'s signals rather than the clock.', source: 'DEVELOPMENT' as ContentSource, tags: ['feeding cues', 'hunger signals', 'fullness', 'responsive feeding', '3 months'] },
    { stageKey: 'born_month_3', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 81, title: 'Batting and Grasping: First Play Gyms', summary: 'Your baby is ready to interact with dangling toys. How to set up a play gym for maximum engagement.', content: 'At 3 months, your baby can bat at objects and may briefly grasp lightweight items placed directly into their palm. A play gym with dangling toys at chest height offers rich opportunities for cause-and-effect learning: batting a toy and watching it swing. Choose gyms with high-contrast elements and varied textures. Lie beside your baby and narrate what you see: "You touched the red bird and it moved." Keep sessions to 5 to 10 minutes and watch for signs of overstimulation such as hiccupping, turning away, or fussing.', source: 'DEVELOPMENT' as ContentSource, tags: ['play gym', 'batting', 'grasping', 'cause and effect', '3 months'] },
    { stageKey: 'born_month_3', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 86, title: 'The 3-Month Growth Spurt: Feeding Frenzy Explained', summary: 'If your previously settled baby suddenly wants to feed constantly, you may be in a classic 3-month growth spurt.', content: 'Growth spurts typically occur around 3 weeks, 6 weeks, 3 months, and 6 months and last 2 to 4 days. During a growth spurt, your baby may want to nurse every hour, seem unsatisfied after a full feeding, and be fussier than usual. This increased demand is your baby\'s way of signaling your body to increase milk supply. For formula-fed babies, you may simply need to offer slightly larger bottles for a few days. Do not be alarmed if your baby seems insatiable for 48 hours and then returns to a normal pattern; that is the hallmark of a growth spurt.', source: 'CLINICAL' as ContentSource, tags: ['growth spurt', 'feeding frequency', 'cluster feeding', '3 months', 'milk supply'] },
    { stageKey: 'born_month_3', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 85, title: 'Coping With Cumulative Sleep Deprivation', summary: 'Three months of broken sleep takes a toll. Practical, realistic strategies for getting through.', content: 'By 3 months, the adrenaline that carried you through the newborn phase has worn off, and chronic sleep deprivation can impact mood, cognition, and relationships. If you have a partner, consider alternating nights, splitting the night into shifts, or designating one weekend morning where each of you gets a solid block of sleep. Accept help from trusted family or friends even if it is just a 90-minute nap while they take the baby for a walk. Lower expectations for non-essentials: the laundry can wait, but your basic need for sleep cannot. If you feel persistently low, anxious, or unable to cope, speak with your provider about postpartum depression screening.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep deprivation', 'parent wellbeing', 'postpartum', 'self-care', '3 months'] },
    { stageKey: 'born_month_3', category: 'SLEEP' as AdviceCategory, priority: 85, title: 'Swaddle Transition: When and How to Stop', summary: 'Once your baby shows signs of rolling, the swaddle must go. A gentle transition plan.', content: 'The AAP recommends discontinuing swaddling at the first signs of rolling, which can occur as early as 8 weeks but typically between 3 and 4 months. A rolling baby in a swaddle cannot push up or roll back, creating an airway risk. Transition options include: going cold turkey to a sleep sack, using a transitional product with arms up or zippered sleeves, or the gradual one-arm-out method over several nights. Expect a few disrupted nights during the transition; your baby is learning a new sleep skill and will adjust. A sleep sack or wearable blanket can continue as long as it does not restrict mobility.', source: 'CLINICAL' as ContentSource, tags: ['swaddle transition', 'sleep safety', 'rolling', 'sleep sack', '3 months'] },
    { stageKey: 'born_month_3', category: 'DEVELOPMENT' as AdviceCategory, priority: 85, title: 'The Emergence of Purposeful Reaching', summary: 'Your baby is beginning to reach for objects with intention rather than by reflex. How reaching evolves and how to support it.', content: 'Around 3 to 4 months, your baby transitions from random arm movements to purposeful reaching and swiping at objects they see. This marks the integration of vision and motor control, a foundational cognitive achievement. Early reaches are two-handed, jerky, and often miss the target. By 5 months, reaches become smoother and more accurate. Offer lightweight, easily graspable objects like a soft rattle, a ring, or a cloth toy at chest level. Do not place the toy directly in their hand every time; the attempt matters more than the success.', source: 'DEVELOPMENT' as ContentSource, tags: ['reaching', 'hand-eye coordination', 'motor control', 'cognitive development', '3 months'] },
    { stageKey: 'born_month_3', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 82, title: 'Floor Time Over Container Time', summary: 'Why unrestricted floor time beats bouncers and swings for motor development, and how to structure it even with a busy schedule.', content: 'Floor time allows your baby to practice the full repertoire of emerging motor skills: lifting the head, pushing up on arms, rolling, reaching, and eventually pivoting and scooting. Containers like bouncers, swings, and car seats, while necessary at times, restrict natural movement patterns and can contribute to positional plagiocephaly and delayed motor milestones when overused. Aim for at least 60 to 90 minutes of cumulative floor time spread throughout the day. A simple blanket or play mat on a safe, firm surface is all you need. Place a few interesting toys just within or slightly beyond reach to motivate movement.', source: 'DEVELOPMENT' as ContentSource, tags: ['floor time', 'motor development', 'containers', 'tummy time', '3 months'] },
    { stageKey: 'born_month_4', category: 'SLEEP' as AdviceCategory, priority: 94, title: 'The 4-Month Sleep Progression: What Is Actually Happening', summary: 'This is not a regression; it is a permanent neurological reorganization of sleep. Understanding the change helps you respond effectively.', content: 'Around 3.5 to 5 months, your baby\'s sleep cycles restructure from newborn patterns (50% active sleep) to more mature cycles with distinct light and deep phases. They now briefly wake between cycles every 45 to 90 minutes, just as adults do. The difference is that an adult rolls over and goes back to sleep without remembering, while your baby may fully wake and cry for the conditions under which they fell asleep, such as nursing or rocking. This is a developmental leap, not a setback. Helping your baby learn to fall asleep independently at bedtime is the single most effective way to navigate this shift.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep regression', '4 months', 'sleep cycles', 'self-soothing', 'sleep science'] },
    { stageKey: 'born_month_4', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 90, title: 'Teething: Early Signs Before Teeth Appear', summary: 'Drooling, chewing, and fussiness often begin months before the first tooth. Separating teething from illness.', content: 'Teething symptoms can begin as early as 3 to 4 months even though the first tooth typically does not erupt until 6 months or later. Signs include increased drooling, a strong urge to chew on hands or objects, mild gum swelling, and general fussiness. Teething does not cause a fever above 100.4 degrees Fahrenheit, diarrhea, or widespread rash; these warrant a call to your pediatrician. Provide relief with chilled (not frozen) teething rings, clean damp washcloths to chew on, and gentle gum massage with a clean finger. Avoid teething necklaces and gels containing benzocaine, which carry safety risks.', source: 'CLINICAL' as ContentSource, tags: ['teething', 'teething symptoms', 'drooling', 'gum pain', '4 months'] },
    { stageKey: 'born_month_4', category: 'DEVELOPMENT' as AdviceCategory, priority: 86, title: 'Rolling Over: The First Major Motor Milestone', summary: 'Your baby\'s first intentional roll from tummy to back or back to tummy is a huge achievement.', content: 'Most babies roll from tummy to back first, sometime between 3 and 5 months, because it is easier to push off the floor. Rolling from back to tummy typically follows a few weeks later and requires more core and neck strength. Once your baby rolls in either direction, stop swaddling immediately for safety; switch to a sleep sack or wearable blanket. Celebrate this milestone enthusiastically; your genuine delight reinforces your baby\'s motivation to keep practicing. If your baby rolls in one direction but not the other, do not worry; asymmetry at this stage is normal.', source: 'DEVELOPMENT' as ContentSource, tags: ['rolling over', 'motor milestone', 'tummy to back', 'core strength', '4 months'] },
    { stageKey: 'born_month_4', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 88, title: 'Readiness Signs for Starting Solids', summary: 'The AAP recommends introducing solids around 6 months. Here is how to tell if your baby is ready a bit earlier or right on time.', content: 'Key readiness signs for solids include: sitting with minimal support, good head and neck control, showing interest in your food by leaning forward and opening their mouth, and the loss of the tongue-thrust reflex that pushes food out of the mouth. These signs typically appear between 4 and 6 months. Starting before 4 months is not recommended due to digestive immaturity. Your baby does not need to have teeth to start solids; gums are remarkably effective at mashing soft foods. Discuss your baby\'s readiness at the 4-month checkup to create a plan that works for your family.', source: 'DEVELOPMENT' as ContentSource, tags: ['starting solids', 'feeding readiness', 'solids signs', 'baby food', '4 months'] },
    { stageKey: 'born_month_4', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 83, title: 'The First Laugh: Games That Bring Giggles', summary: 'Your baby\'s first full belly laugh is unforgettable. How to discover what makes your little one laugh.', content: 'The first laugh typically emerges around 3 to 4 months, often triggered by physical sensations like blowing raspberries on the tummy, gentle bouncing, or exaggerated silly facial expressions. Try a variety of stimuli: making animal sounds, playing peekaboo with a cloth, or singing with big animated gestures. What makes one baby laugh may not work for another; pay close attention to your baby\'s unique sense of humor. Record the first laugh if you can, but also put the phone down and just be present in that joyful moment.', source: 'DEVELOPMENT' as ContentSource, tags: ['first laugh', 'baby giggles', 'play', 'social development', '4 months'] },
    { stageKey: 'born_month_4', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 84, title: 'When Both Parents Are Exhausted: Staying Connected', summary: 'Sleep deprivation strains even the strongest partnerships. Small daily practices that preserve your relationship.', content: 'At 4 months, both parents may be running on fumes, and resentment can creep in silently. Name the dynamic openly: say "I miss you even though we are in the same room." Small rituals matter more than grand gestures: a 5-minute check-in over coffee, a text that says "thank you for handling the 3 AM change," or a quick hug before diving into baby care. Divide tasks based on capacity, not a scorecard, and remember this demanding season is temporary. If conflict escalates, consider a session or two with a couples counselor; many offer virtual appointments that fit into a newborn schedule.', source: 'DEVELOPMENT' as ContentSource, tags: ['parent relationship', 'exhaustion', 'partnership', 'couple connection', '4 months'] },
    { stageKey: 'born_month_4', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 89, title: 'Eczema and Sensitive Skin: Identification and Care', summary: 'Infant eczema often first appears around 3 to 4 months. How to identify it and a gentle skincare approach.', content: 'Infant eczema typically presents as dry, red, itchy patches on the cheeks, scalp, and the extensor surfaces of arms and legs. It is common and often has a genetic component. A daily warm bath of 5 to 10 minutes followed immediately within 2 to 3 minutes by a thick, fragrance-free moisturizer applied to damp skin can significantly reduce flare-ups. Use fragrance-free, dye-free laundry products and dress your baby in breathable cotton. For moderate to severe eczema, your pediatrician may recommend a topical treatment. Untreated eczema is associated with an increased risk of food allergies through the compromised skin barrier.', source: 'CLINICAL' as ContentSource, tags: ['eczema', 'sensitive skin', 'moisturizing', 'allergy risk', '4 months'] },
    { stageKey: 'born_month_4', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 87, title: 'Breastfeeding and Returning to Work: Pumping Strategies', summary: 'Planning your pumping approach before returning to work reduces stress and protects your milk supply.', content: 'If you are returning to work around 4 months, start pumping once a day a few weeks in advance, ideally after the first morning feed when supply is highest, to build a small freezer stash. You do not need hundreds of ounces; 24 to 48 hours\' worth is sufficient. Plan to pump roughly as often as your baby feeds, typically every 3 to 4 hours during the workday. Label stored milk with the date and use the oldest first. Your pump flanges must fit correctly; poor fit reduces output and can cause pain. Reach out to a lactation consultant for a flange fitting if pumping is uncomfortable.', source: 'DEVELOPMENT' as ContentSource, tags: ['pumping', 'returning to work', 'breastfeeding', 'milk supply', '4 months'] },
    { stageKey: 'born_month_4', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 81, title: 'Bubble Play: Visual Tracking and Joy Combined', summary: 'Blowing bubbles is a simple, magical activity that supports visual tracking, anticipation, and gross motor reaching.', content: 'Babies at 4 months are captivated by bubbles. The slow, floating movement is perfect for developing visual tracking, and the eventual pop teaches a gentle lesson in cause and effect. Sit your baby in a supported seated position or let them track bubbles during tummy time. Blow bubbles slowly and narrate: "Look at the bubble floating up, up, up. Where did it go?" This activity is easy to do indoors or out, requires minimal equipment, and often elicits delighted coos and the earliest giggles.', source: 'DEVELOPMENT' as ContentSource, tags: ['bubbles', 'visual tracking', 'sensory play', 'anticipation', '4 months'] },
    { stageKey: 'born_month_4', category: 'DEVELOPMENT' as AdviceCategory, priority: 83, title: 'The First Laugh and Social Reciprocity', summary: 'Around 4 months, babies laugh in response to social interaction. This back-and-forth is the foundation of all later relationships.', content: 'The first true laugh usually emerges between 3 and 4 months and marks a pivotal shift in social development. Unlike the reflexive smile, laughter is a response to shared joy: a silly face, a raspberry on the tummy, a sibling dancing. This is the beginning of social reciprocity, the back-and-forth exchange that underpins all human relationships. Tune into what makes your baby laugh and do it again with slight variation; this builds the earliest sense of humor and teaches your baby that interaction with you is pleasurable and predictable.', source: 'DEVELOPMENT' as ContentSource, tags: ['laughter', 'social reciprocity', 'emotional development', 'bonding', '4 months'] },
    { stageKey: 'born_month_5', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 91, title: 'First Foods: Starting With Single-Ingredient Purees', summary: 'Ready to start solids? A calm, evidence-informed approach to your baby\'s very first tastes.', content: 'Begin with a single-ingredient food, such as iron-fortified infant cereal mixed with breast milk or formula, or a smooth puree of avocado, sweet potato, or pear. Offer just 1 to 2 teaspoons at first; the goal is exposure, not calories. Introduce one new food at a time and wait 2 to 3 days before offering another to watch for any allergic reaction. Signs of a reaction can include hives, vomiting, or swelling and usually appear within minutes to a few hours. Your baby may grimace or spit out food not because they dislike it but because the sensation is brand new; offer the same food several times before deciding it is truly rejected.', source: 'DEVELOPMENT' as ContentSource, tags: ['first foods', 'purees', 'starting solids', 'food introduction', '5 months'] },
    { stageKey: 'born_month_5', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 88, title: 'Drooling and Chewing at 5 Months: More Than Teeth', summary: 'Excessive drooling at this age is usually developmental, not necessarily teething.', content: 'At 5 months, salivary glands ramp up production while your baby has not yet learned to swallow saliva efficiently. Combined with an instinct to mouth and chew on everything, this creates the classic drool phase. This mouthing behavior is actually critical for oral-motor development and sensory exploration. To manage the drool: keep several soft bibs on rotation, apply a thin barrier cream to the chin and cheeks to prevent drool rash, and offer safe textured objects for chewing. If the drool is accompanied by a fever, rash inside the mouth, or significant feeding refusal, consult your pediatrician.', source: 'CLINICAL' as ContentSource, tags: ['drooling', 'oral-motor development', 'mouthing', 'teething', '5 months'] },
    { stageKey: 'born_month_5', category: 'DEVELOPMENT' as AdviceCategory, priority: 85, title: 'Sitting With Support: Building Core Strength', summary: 'Your baby is not quite sitting alone but can stay upright with help. How to practice safely.', content: 'Around 5 months, many babies can sit with support, such as in a high chair with straps or propped with pillows on the floor under close supervision. This upright posture opens a whole new perspective on the world and frees both hands for play. To build core strength, place your baby on their back and gently pull them to sitting by holding their hands, letting them engage their own neck and abdominal muscles. Floor time remains essential; avoid prolonged use of containers like bouncers and exersaucers, which can delay motor development if overused. Aim for a maximum of 15 to 20 minutes at a time in any container.', source: 'DEVELOPMENT' as ContentSource, tags: ['sitting', 'core strength', 'motor development', 'floor time', '5 months'] },
    { stageKey: 'born_month_5', category: 'SLEEP' as AdviceCategory, priority: 89, title: 'Sleep Training Readiness: Is Your Family Ready?', summary: 'Sleep training is a personal choice. Understanding when a baby is developmentally capable of learning independent sleep.', content: 'Most babies are developmentally ready for some form of sleep coaching between 4 and 6 months, after the 4-month sleep cycle maturation, provided they are healthy and gaining weight well. Readiness indicators include: predictable awake windows of roughly 1.5 to 2.5 hours, a somewhat consistent bedtime, and signs that your current approach is no longer sustainable for your family. Sleep training is not one-size-fits-all; methods range from gentle fading approaches to quicker extinction-based methods. Choose the approach that aligns with your parenting values and your baby\'s temperament. Consistency across a 1 to 2 week period is the single strongest predictor of success.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep training', 'sleep coaching', 'independent sleep', 'parenting choice', '5 months'] },
    { stageKey: 'born_month_5', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 82, title: 'Transferring Objects Between Hands', summary: 'A small skill with big cognitive implications: your baby is learning to coordinate both sides of their body.', content: 'Around 5 months, your baby may begin transferring a toy from one hand to the other, a milestone that demonstrates bilateral coordination and the beginning of crossing the body\'s midline. Offer lightweight, grabbable objects like a small rattle, a silicone teether, or a crinkle toy and let your baby explore. You can gently encourage transfer by placing a toy on one side and then showing an interesting second toy on the opposite side. Do not worry if this skill does not appear for another month; the normal window extends through 7 months.', source: 'DEVELOPMENT' as ContentSource, tags: ['transferring objects', 'bilateral coordination', 'fine motor', 'midline crossing', '5 months'] },
    { stageKey: 'born_month_5', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 83, title: 'Managing Stranger Awareness as It Begins', summary: 'Your baby may start showing a preference for familiar faces around 5 months. How to handle visits gracefully.', content: 'Between 5 and 7 months, babies begin to distinguish familiar from unfamiliar faces and may show wariness or distress with people they do not know well. This is a cognitive milestone, not a sign of poor socialization. When a visitor wants to hold your baby, let your baby observe from the safety of your arms first. Ask visitors to approach slowly, avoid direct staring, and let the baby initiate contact. Never force a baby to go to someone they are resisting; forced interactions can intensify anxiety rather than reduce it.', source: 'DEVELOPMENT' as ContentSource, tags: ['stranger awareness', 'social development', 'attachment', 'visitors', '5 months'] },
    { stageKey: 'born_month_5', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 90, title: 'Pacifier Use: Benefits, Risks, and Weaning Timeline', summary: 'Pacifiers reduce SIDS risk in early infancy, but prolonged use can affect dental development. Finding the right balance.', content: 'Pacifier use at sleep times is associated with a significant reduction in SIDS risk, and the AAP recommends offering one at naps and bedtime through the first 6 months at least. After 6 months, the SIDS benefit diminishes while dental concerns begin to emerge with prolonged use beyond age 2. If your baby uses a pacifier, try to limit it to sleep times only starting around 6 months to reduce dependency. Some babies naturally drop the pacifier between 6 and 9 months; if yours does not, aim to wean completely by age 2 to 3 at the latest to prevent dental arch changes.', source: 'CLINICAL' as ContentSource, tags: ['pacifier', 'SIDS prevention', 'dental health', 'weaning', '5 months'] },
    { stageKey: 'born_month_5', category: 'SLEEP' as AdviceCategory, priority: 84, title: 'Creating a Sleep-Inducing Bedroom Environment', summary: 'The physical sleep environment matters more than most parents realize. Optimizing your baby\'s room for restorative sleep.', content: 'Three environmental factors strongly influence infant sleep quality: light, temperature, and sound. Use blackout curtains to keep the room very dark during naps and early morning; even a sliver of light can stimulate wakefulness. Maintain the room at 68 to 72 degrees Fahrenheit. A consistent white noise machine set to 50 to 60 decibels, about the volume of a running shower, helps mask household sounds and can become a powerful sleep association. Place the machine across the room, not directly next to the crib.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep environment', 'bedroom setup', 'blackout curtains', 'white noise', '5 months'] },
    { stageKey: 'born_month_5', category: 'DEVELOPMENT' as AdviceCategory, priority: 84, title: 'The Importance of Uninterrupted Floor Play', summary: 'Your baby needs long stretches of self-directed floor play. Why it matters and how to protect this time.', content: 'Uninterrupted floor play is where your baby builds motor skills, problem-solving abilities, creativity, and the capacity for focused attention. At 5 months, aim for 20 to 30 minute blocks of floor time where you are nearby but not directing the action. Resist the urge to narrate constantly or to intervene at the first sign of frustration. Mild frustration is the birthplace of persistence. Place a few interesting toys within reach, rotate them when interest fades, and let your baby choose what to attend to.', source: 'DEVELOPMENT' as ContentSource, tags: ['floor play', 'independent play', 'attention', 'motor development', '5 months'] },
    { stageKey: 'born_month_5', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 82, title: 'Finding Small Moments of Joy in the Daily Grind', summary: 'The infant care routine can feel relentless. Micro-practices that bring a spark of pleasure into the ordinary.', content: 'Research on parental well-being suggests that small, daily moments of positive emotion have a cumulative protective effect against burnout. Try one of these micro-practices: put on a favorite song and dance with your baby for three minutes, step outside and take five deep breaths while holding your baby, or take a single photo each day of something beautiful in your ordinary life. Do not wait for a full self-care day that may be months away; the small moments are what sustain you now.', source: 'DEVELOPMENT' as ContentSource, tags: ['parent joy', 'burnout prevention', 'micro self-care', 'daily rhythm', '5 months'] },
    { stageKey: 'born_month_6', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 94, title: 'Introducing Common Allergens: Peanut, Egg, and Dairy', summary: 'Early introduction of common allergens around 6 months can reduce the risk of food allergies. A practical guide.', content: 'Current guidelines from the AAP and NIH recommend introducing peanut, egg, and other common allergens around 6 months, especially for babies with eczema or a family history of allergies. Start with a very small amount: a scant quarter teaspoon of smooth peanut butter thinned with warm water, or well-scrambled egg yolk. Offer at home when your baby is well and you can observe them for a couple of hours afterward. Signs of a reaction include hives, facial swelling, vomiting, or difficulty breathing; if any of these occur, seek medical attention. For babies with known severe eczema or existing food allergies, consult your pediatrician or allergist before introducing allergens at home.', source: 'CLINICAL' as ContentSource, tags: ['food allergens', 'peanut introduction', 'egg introduction', 'allergy prevention', '6 months'] },
    { stageKey: 'born_month_6', category: 'DEVELOPMENT' as AdviceCategory, priority: 87, title: 'Sitting Independently: A Whole New World', summary: 'Around 6 months, many babies sit without support. How this milestone transforms play and feeding.', content: 'Independent sitting usually emerges between 5 and 7 months and represents a massive leap in both motor control and cognitive perspective. Your baby can now see the world upright, use both hands freely, and engage with objects in three-dimensional space. To support this skill, provide plenty of floor time with interesting toys placed at seated height. A seated baby still topples, so surround the area with pillows or a soft mat and stay within arm\'s reach. If your baby has not achieved sitting by 9 months, mention it at the checkup; most late sitters catch up without intervention.', source: 'DEVELOPMENT' as ContentSource, tags: ['independent sitting', 'motor milestone', 'core strength', 'development', '6 months'] },
    { stageKey: 'born_month_6', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 90, title: 'The 6-Month Well-Baby Visit: What to Expect', summary: 'A comprehensive checkup with vaccines, developmental screening, and the start of new conversations.', content: 'The 6-month visit typically includes the third round of several vaccines including DTaP, PCV, and possibly the flu shot depending on the season. Your pediatrician will measure growth parameters and plot them on the growth chart, check for emerging teeth, and screen developmental milestones. This is also when conversations about introducing water in a sippy cup, fluoride supplementation if needed, and the 6-to-9-month solids progression typically begin. Bring your list of questions; you will have more now that your baby is more interactive.', source: 'CLINICAL' as ContentSource, tags: ['6-month checkup', 'vaccines', 'well-baby visit', 'growth', 'pediatrician'] },
    { stageKey: 'born_month_6', category: 'SLEEP' as AdviceCategory, priority: 88, title: 'Dropping the Night Feed: Readiness Signs', summary: 'Many 6-month-olds no longer physiologically need a night feed. How to tell if yours is ready and how to wean it gently.', content: 'By 6 months, most healthy, growing babies can sleep through the night without a feed, typically defined as a stretch of 6 to 8 hours. Readiness signs include: consuming full feeds during the day, waking at consistent times rather than varying, and nursing for only a minute or two before falling back asleep at night. To wean a night feed, gradually reduce the amount of formula or the duration of breastfeeding over several nights, then offer comfort through patting or shushing rather than feeding. A baby who is ready may protest for one or two nights and then adjust.', source: 'DEVELOPMENT' as ContentSource, tags: ['night weaning', 'night feed', 'sleep through the night', '6 months', 'feeding'] },
    { stageKey: 'born_month_6', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 84, title: 'Peekaboo as a Cognitive Workout', summary: 'At 6 months, peekaboo transforms from a silly game into the work of building object permanence.', content: 'Object permanence, the understanding that things continue to exist even when out of sight, begins to emerge around 6 to 8 months. Peekaboo is the perfect laboratory for this concept. Start with simple variations: cover your face with your hands, use a light cloth over your baby\'s face that they can pull off, or hide their favorite toy partially under a blanket and encourage them to find it. The joy on your face when you "appear" teaches your baby that separation is temporary, which has implications far beyond play; it builds the emotional foundations for later separation tolerance.', source: 'DEVELOPMENT' as ContentSource, tags: ['object permanence', 'peekaboo', 'cognitive development', 'play', '6 months'] },
    { stageKey: 'born_month_6', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 86, title: 'Half a Year of Parenting: Reflection and Recalibration', summary: 'Six months in, you know your baby and yourself as a parent. A moment to reflect, let go, and set intentions.', content: 'At the half-year mark, you have likely found some rhythm and also confronted unexpected challenges. Take stock: what is working well that you want to protect, and what patterns are draining you that you might let go of? This is a natural inflection point where many parents revisit decisions about sleep, feeding, childcare, and division of labor. Give yourself permission to change your mind about approaches you took at 2 months that no longer fit at 6 months. Parenting is iterative; changing course is not failure, it is responsiveness.', source: 'DEVELOPMENT' as ContentSource, tags: ['parenting reflection', 'half-year', 'recalibration', 'parent wellbeing', '6 months'] },
    { stageKey: 'born_month_6', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 89, title: 'Vision Development: What Your Baby Sees at 6 Months', summary: 'Your baby\'s vision has matured dramatically from the newborn blur. Understanding visual milestones and when to screen.', content: 'By 6 months, your baby\'s vision has sharpened to approximately 20/80 and color vision is fully developed. They can track fast-moving objects smoothly, recognize faces across a room, and discern subtle facial expressions. Depth perception begins to emerge around this age as both eyes learn to work together. Signs that warrant a vision screening include: persistent eye crossing after 4 months, one eye that seems to drift, a head tilt when looking at objects, or a consistent lack of eye contact. The American Optometric Association recommends a first comprehensive eye exam at 6 to 12 months.', source: 'CLINICAL' as ContentSource, tags: ['vision', 'eyesight', 'depth perception', 'eye screening', '6 months'] },
    { stageKey: 'born_month_6', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 88, title: 'Water Introduction: How Much and When', summary: 'Around 6 months, you can begin offering small amounts of water. Guidelines for safe water introduction.', content: 'Once solids are introduced around 6 months, you can offer 2 to 4 ounces of water per day in an open cup or straw cup, primarily for practice rather than hydration. Breast milk or formula should remain the primary source of nutrition and hydration through the first year. Too much water can displace needed calories and, in rare cases, lead to water intoxication. Fluoridated tap water is fine; if your water is from a well, have it tested. Avoid offering water in a bottle, which can lead to overconsumption, and never put juice or sweetened beverages in the cup.', source: 'DEVELOPMENT' as ContentSource, tags: ['water', 'hydration', 'cup drinking', 'solids', '6 months'] },
    { stageKey: 'born_month_6', category: 'DEVELOPMENT' as AdviceCategory, priority: 86, title: 'Understanding Their Name: A Social Milestone', summary: 'Between 5 and 7 months, your baby begins to recognize their own name. What it sounds like and why it matters.', content: 'Name recognition typically emerges around 5 to 7 months when your baby consistently turns their head or pauses their activity upon hearing their name, even without visual cues like your gaze or gesture. This reflects both hearing acuity and social engagement. You can support this skill by using your baby\'s name frequently in positive, animated contexts. Avoid using their name primarily in negative or corrective contexts. A baby who does not respond to their name by 9 to 12 months should have their hearing checked.', source: 'DEVELOPMENT' as ContentSource, tags: ['name recognition', 'social development', 'hearing', 'communication', '6 months'] },
    { stageKey: 'born_month_7', category: 'DEVELOPMENT' as AdviceCategory, priority: 87, title: 'Babbling: Consonants Join the Conversation', summary: 'Your baby\'s sounds are becoming more speech-like. Understanding the babbling milestone and how to encourage it.', content: 'Around 6 to 8 months, babbling evolves from simple vowel sounds to canonical babbling with repeated consonant-vowel combinations like ba-ba-ba or da-da-da. This marks a critical milestone in speech development. You can support babbling by responding to your baby\'s sounds as if they are meaningful conversation, imitating the sounds back, and introducing simple sound-play games. Reading books with rhythmic, repetitive text also feeds their developing phonemic awareness. Early babbling is universal across languages; your baby is exploring the full range of human speech sounds before narrowing to the sounds of your language.', source: 'DEVELOPMENT' as ContentSource, tags: ['babbling', 'consonants', 'speech development', 'language', '7 months'] },
    { stageKey: 'born_month_7', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 88, title: 'Those First Teeth: What to Expect as They Erupt', summary: 'The bottom front teeth are typically first. Managing discomfort and establishing early dental care habits.', content: 'The lower central incisors are usually the first to erupt, typically between 6 and 8 months. You may notice your baby pulling at their ears, having disrupted sleep, or running slightly warmer than usual. Teething does not cause a true fever (100.4 F or 38 C or higher); if your baby has a fever, it is not from teething and warrants a pediatric evaluation. Clean new teeth with a soft, damp washcloth or a silicone finger brush twice daily. Schedule the first dental visit within 6 months of the first tooth or by age 1. Mild gum discomfort and fussiness are common; however, teething does not cause true fever, diarrhea, or severe distress — those warrant a call to your pediatrician.', source: 'CLINICAL' as ContentSource, tags: ['first teeth', 'teething', 'dental care', 'oral health', '7 months'] },
    { stageKey: 'born_month_7', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 91, title: 'Choking Hazards: Foods to Avoid and Why', summary: 'As your baby explores more foods, knowing which items pose choking risks becomes essential.', content: 'The highest-risk foods for infants include whole grapes, hot dogs, popcorn, nuts, hard raw vegetables, chunks of meat or cheese, and sticky foods like large spoonfuls of nut butter. Any food given to a 7-month-old should be soft enough to mash between your thumb and forefinger with light pressure. Cut round foods into thin strips rather than coin shapes. Always supervise meals and keep your baby seated upright in a high chair. Learn infant CPR and choking rescue, and keep emergency numbers visible.', source: 'CLINICAL' as ContentSource, tags: ['choking hazards', 'food safety', 'infant feeding', 'CPR', '7 months'] },
    { stageKey: 'born_month_7', category: 'SLEEP' as AdviceCategory, priority: 89, title: 'Separation Anxiety and Bedtime', summary: 'Separation anxiety can peak at bedtime, turning a previously smooth routine into tearful goodnights.', content: 'Separation anxiety typically emerges between 7 and 9 months as your baby begins to understand that you exist when out of sight and that you can leave. Bedtime often triggers the strongest response because the separation is prolonged. Maintain a consistent, loving bedtime routine that includes extra connection: an extra song, a longer snuggle, or a transitional object such as a small lovey if age-appropriate. Keep goodbyes brief and confident; prolonged, anxious departures signal to your baby that there is something to worry about. If your baby cries, return briefly to reassure but avoid creating a pattern where crying brings you back for extended periods.', source: 'DEVELOPMENT' as ContentSource, tags: ['separation anxiety', 'bedtime', 'sleep', 'attachment', '7 months'] },
    { stageKey: 'born_month_7', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 82, title: 'Mirror Play: The Beginning of Self-Recognition', summary: 'Mirrors fascinate babies at this age. Simple mirror games that support social and emotional development.', content: 'At 7 months, your baby does not yet recognize their own reflection, but they are captivated by the "other baby" in the mirror. Place a shatterproof mirror at floor level during tummy time and watch your baby smile, reach toward, and vocalize at their reflection. Narrate what you see: "That baby has your same blue shirt on." Point to body parts in the mirror together. This play supports visual tracking, social interaction, and the very earliest foundations of self-awareness, which will not fully emerge until around 18 to 24 months.', source: 'DEVELOPMENT' as ContentSource, tags: ['mirror play', 'self-recognition', 'social development', 'visual tracking', '7 months'] },
    { stageKey: 'born_month_7', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 84, title: 'When Parenting Feels Lonely', summary: 'The infant months can be isolating. Recognizing loneliness and taking small steps toward connection.', content: 'Caring for a baby can be profoundly isolating even if you have never felt lonely before. The combination of reduced adult interaction, the monotony of care routines, and the feeling that everyone else has it figured out creates perfect conditions for loneliness. Small, sustainable connections matter: a weekly stroller walk with a neighbor, an online parenting group that meets at a time you can actually attend, or simply texting honestly with a friend who asks "how are you doing." If loneliness deepens into persistent sadness or hopelessness, speak with your healthcare provider.', source: 'DEVELOPMENT' as ContentSource, tags: ['loneliness', 'isolation', 'parent wellbeing', 'mental health', '7 months'] },
    { stageKey: 'born_month_7', category: 'DEVELOPMENT' as AdviceCategory, priority: 86, title: 'The Pincer Grasp: A Fine Motor Breakthrough', summary: 'Your baby is learning to pick up small objects between thumb and forefinger. Why this skill matters and how to practice it safely.', content: 'The pincer grasp typically develops between 8 and 10 months, but early signs often appear around 7 months as your baby rakes objects toward themselves with their whole hand. This fine motor milestone revolutionizes self-feeding and object manipulation. Offer safe, dissolvable finger foods like puffs or soft, pea-sized pieces of cooked vegetables to practice this skill. The pincer grasp also means your baby can now pick up tiny, dangerous objects from the floor, so double-check your floors at baby level.', source: 'DEVELOPMENT' as ContentSource, tags: ['pincer grasp', 'fine motor', 'self-feeding', 'hand coordination', '7 months'] },
    { stageKey: 'born_month_7', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 89, title: 'Colds and Congestion: Comfort Measures for a Stuffy Baby', summary: 'Your baby\'s first cold is often harder on you than them. Safe, effective ways to ease congestion and when to call the doctor.', content: 'Infants are obligate nose breathers, which means congestion can interfere significantly with feeding and sleep. Use saline drops or spray followed by gentle suction with a bulb syringe or NoseFrida before feeds and sleep. A cool-mist humidifier in the room adds moisture that thins mucus. Elevate the head of the crib mattress slightly by placing a towel under the mattress, never by placing pillows in the crib. Over-the-counter cold medications are not recommended for infants. Call your pediatrician for: fever above 100.4 degrees Fahrenheit in a baby under 3 months, any fever lasting more than 3 days, or signs of respiratory distress.', source: 'CLINICAL' as ContentSource, tags: ['colds', 'congestion', 'nasal suction', 'humidifier', '7 months'] },
    { stageKey: 'born_month_7', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 83, title: 'Sensory Bins for Curious Hands', summary: 'A simple sensory bin with safe materials gives your baby a rich tactile exploration experience.', content: 'At 7 months, your baby learns through their senses, and a sensory bin is a perfect container for safe, supervised exploration. Fill a shallow plastic bin with baby-safe materials: a thin layer of water with floating bath toys, crinkle paper strips made from clean packaging, or large fabric scraps of varied textures. Sit with your baby and model touching and describing the materials. Never use small items like dry rice or beans, which pose a choking hazard at this age, and stay within arm\'s reach at all times. Sensory play builds neural connections, fine motor skills, and focused attention.', source: 'DEVELOPMENT' as ContentSource, tags: ['sensory play', 'tactile exploration', 'fine motor', 'sensory bin', '7 months'] },
    { stageKey: 'born_month_7', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 83, title: 'Trusting Your Instincts as a Parent', summary: 'By 7 months, you have accumulated real expertise about your unique baby. Learning to trust what you know.', content: 'By now, you have spent hundreds of hours observing your baby: their specific hunger cues, their tired signs, their particular cry variations. You are the world\'s leading expert on your child. When advice from well-meaning relatives, books, or online forums conflicts with what your gut tells you about your baby, give your own expertise significant weight. Intuition is not magic; it is pattern recognition built through attentive experience. Trusting yourself does not mean never seeking help or information; it means filtering input through your deep knowledge of your unique child.', source: 'DEVELOPMENT' as ContentSource, tags: ['parent intuition', 'self-trust', 'expertise', 'parenting confidence', '7 months'] },
    { stageKey: 'born_month_8', category: 'DEVELOPMENT' as AdviceCategory, priority: 88, title: 'Pulling to Stand: The Vertical Milestone', summary: 'Your baby is figuring out how to get upright using furniture. Supporting this exciting and nerve-wracking leap.', content: 'Pulling to stand typically emerges between 8 and 10 months and is a significant gross motor milestone that requires coordination of arm, leg, and core strength. Provide sturdy, stable furniture at the right height; low, heavy coffee tables or secured shelving work well. Your baby will likely get stuck standing at first, unable to figure out how to get back down. Gently guide their hands to show them how to bend their knees and lower themselves safely rather than simply sitting them down yourself. Falling is part of this process; a soft rug or play mat beneath their practice zone reduces the sting of inevitable tumbles.', source: 'DEVELOPMENT' as ContentSource, tags: ['pulling to stand', 'gross motor', 'standing', 'milestone', '8 months'] },
    { stageKey: 'born_month_8', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 91, title: 'Babyproofing for the Mobile Infant', summary: 'Your baby is on the move. A room-by-room approach to creating a safe exploration zone.', content: 'Get down on your hands and knees and see the world from your baby\'s perspective. Key interventions: anchor furniture and TVs to the wall, cover sharp corners, secure electrical cords, install safety gates at the top and bottom of stairs, and move cleaning products and medications to high, locked cabinets. The bathroom is the most dangerous room; install a toilet lid lock and never leave standing water in a bucket or tub. Babyproofing is not a one-time task; it evolves as your baby gains new skills. Reassess as your baby masters pulling to stand, cruising, and eventually walking.', source: 'CLINICAL' as ContentSource, tags: ['babyproofing', 'safety', 'mobile infant', 'home safety', '8 months'] },
    { stageKey: 'born_month_8', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 87, title: 'Advancing Textures: From Purees to Lumpy Foods', summary: 'Around 8 months, your baby is ready for more complex textures. Why texture progression matters and how to do it safely.', content: 'By 8 months, most babies can handle thicker purees with soft lumps, mashed foods, and very soft finger foods like banana spears or avocado wedges. Advancing textures builds oral-motor skills needed for speech and prevents later texture aversions. If your baby gags, do not panic; gagging is a protective reflex that is actually more forward on the tongue in infants than in adults. True choking is silent, while gagging is loud and involves coughing. Offer lumpy textures by 9 months at the latest; some research suggests that delayed introduction of textured foods beyond 10 months is associated with feeding difficulties later.', source: 'DEVELOPMENT' as ContentSource, tags: ['food textures', 'lumpy foods', 'oral-motor', 'feeding progression', '8 months'] },
    { stageKey: 'born_month_8', category: 'SLEEP' as AdviceCategory, priority: 86, title: 'Motor Milestone Sleep Disruptions', summary: 'When your baby suddenly starts waking at night after a new skill emerges, it is likely motor milestone disruption.', content: 'It is extremely common for sleep to temporarily fall apart when a baby is mastering a new motor skill like crawling, pulling to stand, or cruising. Your baby\'s brain is so focused on practicing the new skill that it intrudes into sleep, causing them to wake at night and practice or cry out when they get stuck. The disruption typically lasts 1 to 3 weeks. Provide ample floor time during the day to satisfy the drive to practice, and during night wakings, offer calm, brief help without turning on lights or initiating play. This too shall pass.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep disruption', 'motor milestones', 'night waking', 'brain development', '8 months'] },
    { stageKey: 'born_month_8', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 81, title: 'Simple Cause-and-Effect Games', summary: 'Your baby is fascinated by how their actions change the world. Toys and games that reward curiosity.', content: 'At 8 months, your baby is deeply engaged in understanding causality: "If I do this, that happens." Provide toys with clear, reliable cause-and-effect mechanisms: balls that light up or make noise when rolled, pop-up toys activated by simple buttons, or a container they can drop blocks into. Narrate the action: "You pushed the button and the door opened." These games build problem-solving skills and give your baby a sense of agency. Rotate toys to keep them interesting; your baby does not need a large collection, just a few well-chosen items.', source: 'DEVELOPMENT' as ContentSource, tags: ['cause and effect', 'problem solving', 'cognitive play', 'toys', '8 months'] },
    { stageKey: 'born_month_8', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 83, title: 'Sibling Dynamics: The Older Child and the Mobile Baby', summary: 'When your baby starts crawling or cruising, older siblings face a new reality. Helping everyone adjust.', content: 'An older sibling who was previously indifferent to the baby may suddenly feel territorial when the baby is able to reach their toys. Validate the older child\'s feelings: "It is hard when your brother grabs your special things." Create a safe play zone for the older child that is inaccessible to the baby, such as a tabletop or a gated-off corner. Involve the older child as a helper in age-appropriate ways: fetching a diaper, making the baby laugh. Ensure one-on-one time with the older child, even just 10 minutes a day, to reinforce that they are still seen and cherished.', source: 'DEVELOPMENT' as ContentSource, tags: ['siblings', 'older child', 'family dynamics', 'mobility', '8 months'] },
    { stageKey: 'born_month_8', category: 'DEVELOPMENT' as AdviceCategory, priority: 85, title: 'Understanding the Word "No": A First Step in Discipline', summary: 'Your baby is beginning to understand prohibitions around 8 to 9 months. How to use this new comprehension wisely.', content: 'Around 8 to 9 months, many babies begin to pause briefly when they hear a firm but calm "no," though they may not consistently comply. They are learning that words carry meaning about behavior. Use the word sparingly and save it for safety-critical situations like reaching for an outlet or a hot drink. For everything else, use redirection: physically guide your baby away from the forbidden item and toward an acceptable alternative. Overusing "no" dilutes its power and creates a negative verbal environment.', source: 'DEVELOPMENT' as ContentSource, tags: ['discipline', 'understanding no', 'behavior guidance', 'redirection', '8 months'] },
    { stageKey: 'born_month_8', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 89, title: 'Ear Infections: Signs and When to Seek Treatment', summary: 'Ear infections become more common in the second half of the first year. Recognizing the subtle signs before a fever appears.', content: 'Ear infections, or acute otitis media, peak between 6 and 18 months due to the anatomy of the eustachian tube. Early signs may include increased night waking, irritability when lying flat, tugging at the ear, decreased appetite, and unexplained fussiness. A fever may develop later or not at all. If you suspect an ear infection, see your pediatrician for an ear exam; not all ear pain requires antibiotics, as many infections are viral. Recurrent ear infections or fluid that persists after infection can affect hearing and speech development, so follow up as recommended.', source: 'CLINICAL' as ContentSource, tags: ['ear infections', 'otitis media', 'fever', 'pediatric care', '8 months'] },
    { stageKey: 'born_month_8', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 86, title: 'Introducing a Cup: Open Cups vs. Sippy Cups vs. Straw Cups', summary: 'Starting a cup around 8 months builds oral-motor skills. Comparing cup types and how to begin.', content: 'An open cup, small shot-glass sized for little hands, is actually the best starting point for oral-motor development. Fill it with a small amount of water, hold it with your baby, and guide it to their mouth. Expect spilling; that is part of the learning. Straw cups are also excellent and support the lip, tongue, and cheek coordination needed for speech. Traditional hard-spout sippy cups are less ideal for oral development because they reinforce an immature suckle pattern, but they can be useful for on-the-go or as a transitional tool. Offer a cup with a small amount of water at one meal per day starting around 8 months and gradually increase frequency.', source: 'DEVELOPMENT' as ContentSource, tags: ['cup introduction', 'open cup', 'straw cup', 'oral-motor', '8 months'] },
    { stageKey: 'born_month_9', category: 'DEVELOPMENT' as AdviceCategory, priority: 87, title: 'Clapping and Waving: Social Gestures Take Off', summary: 'Around 9 months, your baby starts using their hands to communicate intentionally. The joy and importance of early gestures.', content: 'Clapping, waving bye-bye, and raising arms to be picked up are among the first intentional gestures, typically emerging between 8 and 10 months. These gestures are a form of communication that precedes spoken words and demonstrate that your baby understands social routines. Model these gestures during daily transitions: wave bye-bye when leaving a room, clap when something exciting happens, and pause to see if your baby imitates you. Early gesture use is strongly correlated with later language development. If your baby does not gesture by 12 months, mention it at the checkup.', source: 'DEVELOPMENT' as ContentSource, tags: ['gestures', 'clapping', 'waving', 'communication', 'social development', '9 months'] },
    { stageKey: 'born_month_9', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 89, title: 'The 9-Month Checkup: Developmental Screening', summary: 'Your pediatrician will conduct a more detailed developmental assessment at this visit. What they are looking for.', content: 'The 9-month visit typically includes a standardized developmental screening using a tool like the Ages and Stages Questionnaire. Your pediatrician will assess motor skills, communication, problem-solving, and personal-social development. This is also when anemia screening and a lead level test may be discussed. Bring any concerns you have, even if they feel vague. Early identification of delays leads to early intervention, which has strong evidence for improving outcomes.', source: 'CLINICAL' as ContentSource, tags: ['9-month checkup', 'developmental screening', 'pediatrician', 'milestones', 'early intervention'] },
    { stageKey: 'born_month_9', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 88, title: 'Self-Feeding: Embracing the Mess', summary: 'Your baby wants to grab the spoon. Why self-feeding matters and how to support it without losing your sanity.', content: 'Around 9 months, your baby\'s pincer grasp is developing, and they may insist on feeding themselves. Let them. Self-feeding builds fine motor skills, fosters autonomy, and helps your baby learn to regulate their own intake. Offer a loaded spoon for them to grab, provide soft finger foods on the tray, and accept that more food will end up on the floor, bib, and chair than in their mouth for a while. Use a splat mat under the high chair, strip your baby down to a diaper for especially messy meals, and remember that this phase is both temporary and developmentally essential.', source: 'DEVELOPMENT' as ContentSource, tags: ['self-feeding', 'baby-led weaning', 'finger foods', 'autonomy', '9 months'] },
    { stageKey: 'born_month_9', category: 'SLEEP' as AdviceCategory, priority: 90, title: 'The 9-Month Sleep Disruption and Separation Anxiety', summary: 'A perfect storm of separation anxiety, motor milestones, and teething can disrupt sleep around 9 months.', content: 'The confluence of separation anxiety peaking, cruising and crawling practice, and often the eruption of upper teeth creates a predictable sleep disruption around 8 to 10 months. Maintain your routine with consistency and warmth; this is not the time to introduce major new sleep changes unless your current approach is truly unsustainable. Offer a transitional object if age-appropriate, keep the pre-bed routine calm, and ensure your baby gets enough practice with new motor skills during the day. This phase typically resolves in 2 to 4 weeks.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep disruption', '9 months', 'separation anxiety', 'teething', 'motor milestones'] },
    { stageKey: 'born_month_9', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 84, title: 'Creating Safe Play Zones for Exploring Babies', summary: 'A well-designed play space lets your baby explore freely and gives you moments of lower-intensity supervision.', content: 'Designate a fully babyproofed area, sometimes called a "yes space," where your baby can explore without hearing "no" constantly. This could be a gated-off section of a room or a large play yard with safe climbing cushions and age-appropriate toys. Include a mix of textures, low mirrors, sturdy furniture for pulling up, and open baskets with toys within reach. A yes space is not a place to leave your baby unattended for long stretches, but it is a place where you can sit nearby and observe without constantly intervening. The sense of freedom and competence your baby gains in this space supports confidence and motor development.', source: 'DEVELOPMENT' as ContentSource, tags: ['safe play space', 'yes space', 'babyproofing', 'independent play', '9 months'] },
    { stageKey: 'born_month_9', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 85, title: 'Parent Self-Compassion: Soothing Your Inner Critic', summary: 'Nine months of parenting brings plenty of moments for self-doubt. Learning to talk to yourself like you would talk to a friend.', content: 'The inner critic can be relentless: "I should have started solids differently," "Everyone else\'s baby sleeps through the night." Self-compassion research by Dr. Kristin Neff suggests three components: mindfulness of your suffering without exaggerating it, recognition that struggle is part of the shared human experience of parenting, and self-kindness rather than self-judgment. When you catch the critical voice, ask yourself: "What would I say to my best friend if they told me this?" You are the parent your baby needs, imperfections and all.', source: 'DEVELOPMENT' as ContentSource, tags: ['self-compassion', 'inner critic', 'parent mental health', 'mindfulness', '9 months'] },
    { stageKey: 'born_month_9', category: 'DEVELOPMENT' as AdviceCategory, priority: 86, title: 'First Words: The Sounds That Become Speech', summary: 'Around 9 months, some babies produce their first meaningful word. Understanding the difference between babbling and word use.', content: 'First words often emerge between 9 and 14 months and are typically "mama," "dada," or a label for a beloved person, pet, or object. A number of babies say "dada" first, not because they prefer dad, but because the "d" sound is easier to produce than "m." Celebrate any word-like attempt warmly. You can encourage language by narrating throughout the day, reading board books with single images and labels, and responding to babbling as if it is part of a real conversation. Do not pressure your baby to "say" words; receptive language develops first.', source: 'DEVELOPMENT' as ContentSource, tags: ['first words', 'language development', 'speech', 'babbling', '9 months'] },
    { stageKey: 'born_month_9', category: 'SLEEP' as AdviceCategory, priority: 85, title: 'Early Morning Rising: Why 5 AM Happens and How to Shift It', summary: 'If your 9-month-old is consistently waking before 6 AM ready to start the day, there are specific adjustments that can help.', content: 'Early morning waking is often caused by one or more of the following: bedtime is too late creating overtiredness, the room is getting light too early, the first nap is too early cementing an early circadian start, or your baby is hungry. Start by ensuring total darkness until at least 6 AM, then evaluate whether bedtime needs to move 15 to 30 minutes earlier, counterintuitively. Treat any waking before 6 AM as a night waking: keep the room dark, keep your voice low, and delay the first feed and exposure to light until your desired wake time. Consistency over 7 to 10 days is key to shifting the circadian rhythm.', source: 'DEVELOPMENT' as ContentSource, tags: ['early morning waking', 'circadian rhythm', 'sleep schedule', '9 months', 'bedtime'] },
    { stageKey: 'born_month_9', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 87, title: 'Sleeping Through the Night: Reframing Expectations', summary: 'Many 9-month-olds still wake at night, and that can be developmentally normal. What the research actually says about sleeping through.', content: 'Studies using objective sleep measures show that a significant percentage of infants do not consistently sleep through the night at 9 months, even when parents think they should. "Sleeping through" is typically defined as a 6-to-8-hour stretch, not 12 hours uninterrupted. If your baby wakes once or twice, feeds briefly if still nursing at night, and falls back asleep easily, they are within a normal developmental range. What matters most is whether your family\'s sleep arrangement is sustainable for you. If night wakings are causing excessive daytime fatigue, that is worth addressing, but waking per se is not necessarily a problem to fix.', source: 'CLINICAL' as ContentSource, tags: ['sleeping through the night', 'night waking', 'sleep expectations', 'normal sleep', '9 months'] },
    { stageKey: 'born_month_9', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 86, title: 'Balancing Milk Feeds and Solid Foods at 9 Months', summary: 'At 9 months, solids should contribute substantial nutrition. How to structure the day around milk and meals.', content: 'By 9 months, solids should make up a significant portion of your baby\'s nutrition, typically breakfast, lunch, and a smaller afternoon meal. Breast milk or formula remains important, providing about half of daily calories for many babies. A typical rhythm: morning milk feed upon waking, breakfast of solids about an hour later, milk feed mid-morning, lunch, milk feed mid-afternoon, dinner, and a final milk feed before bed. Offer solids before milk at meals so your baby comes to the table with an appetite. If your baby fills up on milk and has little interest in solids, try spacing milk and solid feeds further apart.', source: 'DEVELOPMENT' as ContentSource, tags: ['solid foods', 'milk feeds', 'meal schedule', 'nutrition', '9 months'] },
    { stageKey: 'born_month_10', category: 'DEVELOPMENT' as AdviceCategory, priority: 87, title: 'Cruising: Furniture Walking and Between Objects', summary: 'Your baby is navigating the room on two feet using furniture. How cruising builds toward independent walking.', content: 'Cruising, or walking while holding onto furniture, typically emerges between 9 and 12 months and marks a significant step toward independent walking. Arrange furniture in a way that allows your baby to move from one stable piece to another with a short reach between them. Encourage your baby to let go briefly by offering a favorite toy from the side. Bare feet are best for cruising because they provide sensory feedback from the floor. Some babies cruise for weeks and walk by 10 months; others cruise for months and walk at 14. Both are normal.', source: 'DEVELOPMENT' as ContentSource, tags: ['cruising', 'furniture walking', 'gross motor', 'balance', '10 months'] },
    { stageKey: 'born_month_10', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 88, title: 'Responding to Name: A Key Social-Communication Check', summary: 'By 10 months, your baby should consistently respond when you call their name. What to watch for and when to talk to your doctor.', content: 'By 9 to 10 months, most babies consistently turn toward you when you call their name from across a quiet room. This skill reflects both hearing and social engagement. Occasional ignoring when deeply focused on play is normal; never responding could signal a hearing issue or be one early marker of autism that warrants further evaluation. If your baby does not respond to their name by 12 months, or if you notice they respond only to loud sounds or visual cues, bring it up at the next checkup. A hearing test is a simple, non-invasive first step.', source: 'CLINICAL' as ContentSource, tags: ['name response', 'hearing', 'social communication', 'development', '10 months'] },
    { stageKey: 'born_month_10', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 85, title: 'Food Throwing and Mealtime Power Struggles', summary: 'Your baby delights in gravity experiments at mealtime. Understanding the behavior and reducing the mess.', content: 'At 10 months, food throwing is developmentally normal: your baby is exploring gravity, cause and effect, and autonomy all at once. Responding with big reactions, whether positive or negative, tends to reinforce the behavior. Calmly say "food stays on the tray" and offer a small bowl or designated spot for rejected items. Give a very small amount of food at a time; a full tray is an irresistible invitation to sweep and throw. If throwing continues despite a calm response, mealtime may be over. Your baby will not starve from one shortened meal.', source: 'DEVELOPMENT' as ContentSource, tags: ['food throwing', 'mealtime behavior', 'autonomy', 'feeding', '10 months'] },
    { stageKey: 'born_month_10', category: 'SLEEP' as AdviceCategory, priority: 87, title: 'Sleep Disruptions During Motor Leap Phases', summary: 'When your baby is on the verge of walking, sleep can unravel. Understanding why and how to cope.', content: 'The weeks leading up to and following a major motor milestone such as independent standing or first steps are frequently accompanied by sleep disruptions. Your baby\'s brain is consolidating the new skill, which can produce restlessness, night waking, and early rising. Offer generous amounts of floor time during the day for practice, keep the bedtime routine calm and predictable, and avoid introducing new sleep associations during this period that you are not prepared to maintain long-term. These disruptions usually resolve spontaneously within 2 to 3 weeks of the milestone being achieved.', source: 'DEVELOPMENT' as ContentSource, tags: ['motor milestones', 'sleep disruption', 'walking prep', 'brain development', '10 months'] },
    { stageKey: 'born_month_10', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 82, title: 'Stacking and Sorting: First Problem-Solving Play', summary: 'Simple stacking cups and shape sorters build cognitive and fine motor skills at this stage.', content: 'At 10 months, your baby may begin to show interest in putting objects into containers and taking them out again, a foundational problem-solving schema. Offer a set of stacking cups, a simple shape sorter with large pieces, or a small basket and clothespins. At first your baby will enjoy dumping more than filling, and that is exactly right developmentally. Narrate spatial concepts simply: "The red block goes inside. Now you took it out." Do not correct your baby if they cannot yet match shapes; exploration and trial-and-error are the point.', source: 'DEVELOPMENT' as ContentSource, tags: ['stacking', 'sorting', 'problem solving', 'fine motor', '10 months'] },
    { stageKey: 'born_month_10', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 84, title: 'Managing Parental Anxiety as Mobility Grows', summary: 'Watching your baby cruise and climb can trigger intense anxiety. Distinguishing reasonable caution from overprotection.', content: 'It is natural to feel anxious as your baby becomes more mobile and more vulnerable to falls and injuries. Some anxiety keeps your baby safe; excessive anxiety that prevents your baby from exploring can hinder motor development and confidence. Distinguish between real dangers such as stairs and electrical outlets and tolerable risks such as a soft fall from a standing position. Practice sitting near your baby and silently counting to five before intervening, giving them a chance to problem-solve. If anxiety is persistently interfering with your enjoyment of parenting, consider talking to a therapist who specializes in perinatal mental health.', source: 'DEVELOPMENT' as ContentSource, tags: ['parental anxiety', 'mobility', 'risk tolerance', 'overprotection', '10 months'] },
    { stageKey: 'born_month_10', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 86, title: 'Iron-Rich Foods: Why They Matter at 10 Months', summary: 'Your baby\'s iron stores from birth are depleting. Prioritizing iron-rich foods and recognizing deficiency signs.', content: 'Babies are born with iron stores that last approximately 6 months. Between 6 and 12 months, dietary iron becomes essential to prevent iron deficiency anemia, which can impair cognitive and motor development. Iron-rich foods for this age include pureed meats, iron-fortified infant cereals, lentils, beans, and spinach. Pair iron-rich foods with vitamin C sources such as a squeeze of citrus or a few pieces of strawberry to enhance absorption. Signs of deficiency can be subtle: pallor, fatigue, irritability, and decreased appetite. Your pediatrician will screen for anemia at the 12-month visit.', source: 'CLINICAL' as ContentSource, tags: ['iron', 'anemia', 'nutrition', 'brain development', '10 months'] },
    { stageKey: 'born_month_10', category: 'DEVELOPMENT' as AdviceCategory, priority: 85, title: 'Object Permanence Mastered: Out of Sight, Still in Mind', summary: 'Your baby now knows an object exists even when hidden. How this cognitive leap changes play and emotional life.', content: 'By 10 months, your baby has a solid grasp of object permanence: the understanding that objects and people continue to exist even when they cannot be seen. This cognitive milestone is behind both the joy of finding a hidden toy and the distress of separation at bedtime. Play hide-and-seek with toys under a cloth, let your baby watch you place an object in a container and find it. This understanding also means your baby knows you exist when you leave the room, which can intensify separation protests. That is cognitively appropriate, not regressive.', source: 'DEVELOPMENT' as ContentSource, tags: ['object permanence', 'cognitive development', 'separation', 'hide and seek', '10 months'] },
    { stageKey: 'born_month_10', category: 'SLEEP' as AdviceCategory, priority: 83, title: 'Separation Anxiety and Night Wakings: A Compassionate Approach', summary: 'Separation anxiety can resurface at night around 10 months. Responding in a way that builds security and preserves sleep.', content: 'Separation anxiety can peak again around 10 months and may cause night wakings where your baby cries and only settles with your presence. A brief, calm check-in without picking up, with a consistent phrase like "Mama is here, it is time to sleep," can provide reassurance without creating a new habit of extended nighttime interaction. If your baby needs more comfort, sit beside the crib and pat gently until they settle rather than removing them from the sleep space. The goal is to communicate safety while maintaining the expectation that nighttime is for sleep. This phase typically lasts 1 to 3 weeks.', source: 'DEVELOPMENT' as ContentSource, tags: ['separation anxiety', 'night wakings', 'sleep', 'attachment', '10 months'] },
    { stageKey: 'born_month_10', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 84, title: 'Dealing With Unsolicited Parenting Advice', summary: 'As your baby becomes a more public presence, the advice pours in. Gracefully handling unwanted input.', content: 'Everyone from grandparents to grocery store strangers has opinions about how you should parent. A helpful script when you want to decline without starting a debate: "That is an interesting perspective. We have found what works for our family." For persistent advice-givers, be direct: "We have discussed this with our pediatrician and are comfortable with our approach." Remember that much unsolicited advice comes from a place of care or nostalgia, not malice, but that does not obligate you to follow it. Your baby, your family, your informed choices.', source: 'DEVELOPMENT' as ContentSource, tags: ['unsolicited advice', 'boundaries', 'parenting confidence', 'family dynamics', '10 months'] },
    { stageKey: 'born_month_11', category: 'DEVELOPMENT' as AdviceCategory, priority: 88, title: 'Standing Briefly Without Support', summary: 'Your baby may let go of furniture and balance for a few seconds. A thrilling glimpse of the walking to come.', content: 'Independent standing, even for a second or two, typically emerges between 10 and 13 months. This brief, wobbly balance act requires tremendous core and leg strength plus the courage to let go. Celebrate these moments with genuine enthusiasm; your reaction fuels their motivation to try again. You can encourage independent standing by offering a toy with both hands so your baby must let go of the furniture to grasp it. Do not rush this stage; the balance and postural control your baby builds now will serve them when they take their first independent steps.', source: 'DEVELOPMENT' as ContentSource, tags: ['independent standing', 'balance', 'walking prep', 'gross motor', '11 months'] },
    { stageKey: 'born_month_11', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 90, title: 'Fever Management: When to Worry and When to Wait', summary: 'Fevers are common in late infancy as your baby encounters more germs. Evidence-based fever guidelines for parents.', content: 'A fever is defined as a rectal temperature of 100.4 degrees Fahrenheit or higher. For infants over 6 months, a fever alone is generally not dangerous; treat your baby\'s comfort, not the number on the thermometer. Offer fluids frequently, dress your baby lightly, and use infant acetaminophen or ibuprofen at weight-appropriate doses if your baby is clearly uncomfortable. Call your pediatrician for: any fever in a baby under 3 months, a fever lasting more than 3 days, a fever above 104 degrees Fahrenheit, signs of dehydration, or if your baby is lethargic, inconsolable, or has difficulty breathing.', source: 'CLINICAL' as ContentSource, tags: ['fever', 'temperature', 'illness', 'when to call doctor', '11 months'] },
    { stageKey: 'born_month_11', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 87, title: 'Weaning From Breastfeeding or Formula: Starting the Conversation', summary: 'As the first birthday approaches, you may be thinking about weaning. A gradual, emotionally-attuned approach.', content: 'Whether you are breastfeeding or formula feeding, weaning is a process, not an event. If you choose to wean around 12 months, start by replacing one feeding session at a time with whole milk in a cup and solid food. Choose a feed your baby is least attached to first, often a midday feed. Allow several days to a week between dropping each feed so your body adjusts and your baby adapts. Weaning can bring up complex emotions including sadness, relief, and guilt; all of these are normal. Your baby has received immense benefit from every day of milk feeding you have provided.', source: 'DEVELOPMENT' as ContentSource, tags: ['weaning', 'breastfeeding', 'formula feeding', 'transition', '11 months'] },
    { stageKey: 'born_month_11', category: 'SLEEP' as AdviceCategory, priority: 86, title: 'Bedtime Protests: The 11-Month Assertion Phase', summary: 'Your baby has discovered the word "no" and may use it at bedtime. Responding to bedtime resistance without creating new habits.', content: 'Around 11 months, bedtime resistance can emerge as a form of assertion and separation protest. Your baby may arch their back, scream when placed in the crib, or cry intensely at your departure. Hold the bedtime boundary with calm consistency while acknowledging the feeling: "I know you want to keep playing. It is time for sleep now." Ensure the awake window before bed is neither too short nor too long; around 3.5 to 4.5 hours is typical at this age. If resistance persists, evaluate whether the nap schedule still fits or whether the bedtime routine has become overstimulating.', source: 'DEVELOPMENT' as ContentSource, tags: ['bedtime resistance', 'assertion', 'separation', 'sleep schedule', '11 months'] },
    { stageKey: 'born_month_11', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 84, title: 'Pointing to Communicate: The Power of a Tiny Finger', summary: 'Pointing is a huge communication milestone. How to encourage declarative pointing and what it tells you about your baby\'s mind.', content: 'Pointing typically begins around 10 to 12 months and comes in two forms: imperative pointing to request something and declarative pointing to share attention. Declarative pointing is a uniquely human, socially sophisticated act. Encourage pointing by following your baby\'s point immediately: look where they point, name it, and expand: "Yes, that is a dog. The dog is wagging his tail." This is called joint attention and it is one of the strongest predictors of language development.', source: 'DEVELOPMENT' as ContentSource, tags: ['pointing', 'joint attention', 'communication', 'language development', '11 months'] },
    { stageKey: 'born_month_11', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 86, title: 'Nearly One Year: Reflecting on Your Parenting Journey', summary: 'As the first birthday approaches, you may feel waves of emotion. Honoring the year you have had.', content: 'The approach of your baby\'s first birthday often brings a mix of pride, nostalgia, exhaustion, and disbelief. You have kept a tiny human alive for almost a full rotation around the sun. Some parents feel a strong desire to mark this milestone with a party; others feel too depleted and that is equally valid. Write a letter to your future self about what this year has been like in its real, unvarnished detail. If the year brought trauma, loss, or challenges beyond the ordinary, consider talking with a therapist as the intensity of the infant year recedes and space for processing opens.', source: 'DEVELOPMENT' as ContentSource, tags: ['first birthday', 'reflection', 'parenting journey', 'milestone', '11 months'] },
    { stageKey: 'born_month_11', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 88, title: 'Preparing for the 12-Month Transition: What to Discuss Now', summary: 'The month before the big birthday, there are decisions to start thinking about. A checklist for the 11-month mark.', content: 'As you approach your baby\'s first birthday, several transitions are on the horizon: weaning from formula to whole milk, transitioning from bottle to cup, discussing when to introduce peanut and other allergens if not yet done, and considering whether to continue breastfeeding and at what frequency. This is also a good time to schedule the 12-month well-child visit, think about toddler-proofing as walking approaches, and reflect on childcare arrangements for the coming year. You do not need to have all the answers at 11 months, but beginning to think about these topics now makes the transitions smoother.', source: 'CLINICAL' as ContentSource, tags: ['12-month prep', 'transition planning', 'pediatrician', 'milestone', '11 months'] },
    { stageKey: 'born_month_11', category: 'DEVELOPMENT' as AdviceCategory, priority: 86, title: 'First Steps: The Psychological Leap, Not Just Physical', summary: 'Walking is not only a motor achievement. It transforms your baby\'s sense of self, social interaction, and cognitive exploration.', content: 'When your baby takes their first independent steps, they experience themselves as an autonomous agent in space for the first time. This can produce a mix of exhilaration and clinginess that swings day by day. Research shows that walking babies interact differently with caregivers, bringing objects to show and seeking more distal forms of communication. They also learn differently, with hands free to carry and explore. Celebrate the first steps, but also recognize that your baby is navigating a psychological shift. Extra patience and physical availability during this transition is a wise investment.', source: 'DEVELOPMENT' as ContentSource, tags: ['first steps', 'walking', 'autonomy', 'psychological development', '11 months'] },
    { stageKey: 'born_month_11', category: 'SLEEP' as AdviceCategory, priority: 88, title: 'Transitioning From Two Naps to One: The Signs', summary: 'The 2-to-1 nap transition typically happens between 12 and 18 months, but early signs can appear at 11 months.', content: 'Signs that your baby may be approaching the transition from two naps to one include: consistently refusing the afternoon nap while still taking the morning nap, taking a long morning nap that pushes the afternoon nap too late, or resisting bedtime even with appropriate awake windows. Do not rush this transition; most 11-month-olds still need two naps. If you are seeing consistent resistance to the second nap for 2 weeks or more, try capping the morning nap to 45 to 60 minutes to protect the afternoon nap and preserve a reasonable bedtime.', source: 'DEVELOPMENT' as ContentSource, tags: ['nap transition', 'two naps to one', 'sleep schedule', '11 months', 'nap resistance'] },
    { stageKey: 'born_month_12', category: 'DEVELOPMENT' as AdviceCategory, priority: 89, title: 'First Words: What Counts and What to Expect', summary: 'Your baby\'s first intentional words are an exciting milestone. Understanding what qualifies as a true word and the wide range of normal.', content: 'A true word is a consistent sound or approximation used intentionally to refer to a specific person, object, or action. Animal sounds like "moo" count; sounds only used in one context like "ba" only for bottle count. Most 12-month-olds have 1 to 3 words, though the normal range spans from zero to over 20. Receptive language, what your baby understands, is far larger at this age. Encourage words by responding enthusiastically, expanding on what your baby says, and narrating your day. If your baby has no consistent words and does not use gestures like pointing by 15 months, discuss with your pediatrician.', source: 'DEVELOPMENT' as ContentSource, tags: ['first words', 'language development', 'speech', 'communication', '12 months'] },
    { stageKey: 'born_month_12', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 91, title: 'The 12-Month Checkup: Vaccines and Key Screenings', summary: 'A major well-child visit that includes vaccines, anemia and lead screening, and big conversations about toddlerhood.', content: 'The 12-month visit typically includes the first dose of MMR and varicella vaccines, plus boosters of previously administered vaccines. Blood work is often drawn for anemia screening and lead levels. Your pediatrician will also discuss the transition to whole milk, weaning from the bottle, toddler nutrition, language milestones, and safety topics including car seat positioning. Prepare your questions in advance; this is a long and information-rich appointment.', source: 'CLINICAL' as ContentSource, tags: ['12-month checkup', 'vaccines', 'MMR', 'lead screening', 'toddler health'] },
    { stageKey: 'born_month_12', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 90, title: 'Weaning From the Bottle: Why and How', summary: 'The AAP recommends weaning from the bottle by 12 to 18 months. A practical timeline and strategies to make it stick.', content: 'Prolonged bottle use is associated with tooth decay, iron deficiency anemia from excessive milk intake, and may interfere with developing chewing skills. Start by replacing one daytime bottle with a cup of whole milk and a solid snack, then eliminate the midday and afternoon bottles. The bedtime bottle is usually the hardest to drop because it is woven into the sleep routine; replace it with a cup of milk before brushing teeth and a cuddle. By 12 months, your baby should have all liquids from an open cup, straw cup, or sippy cup, not from a bottle.', source: 'DEVELOPMENT' as ContentSource, tags: ['bottle weaning', 'cup transition', 'dental health', 'feeding', '12 months'] },
    { stageKey: 'born_month_12', category: 'SLEEP' as AdviceCategory, priority: 88, title: '1-Year-Old Sleep Needs and a Sample Schedule', summary: 'Sleep needs shift around the first birthday. What total sleep looks like now and a sample two-nap day.', content: 'At 12 months, most babies need 11 to 14 hours of total sleep in a 24-hour period, typically consisting of 10 to 12 hours overnight and 2 to 3 hours split across two naps. A common schedule: wake at 7 AM, first nap 9:30 to 11 AM, second nap 2 to 3:30 PM, bedtime around 7:30 PM. Some 12-month-olds are ready for one nap, but most still need two. Signs your baby still needs two naps include: falling asleep quickly at nap time, short naps when switched to one nap, and increased night waking or early morning rising.', source: 'DEVELOPMENT' as ContentSource, tags: ['sleep schedule', 'nap needs', '1-year sleep', 'toddler sleep', '12 months'] },
    { stageKey: 'born_month_12', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 84, title: 'Simple Pretend Play Begins', summary: 'Around the first birthday, your baby may start pretending. How to nurture this blossoming imagination.', content: 'Early pretend play emerges around 12 to 15 months and looks very simple: holding a toy phone to their ear, pretending to drink from an empty cup, or offering a teddy bear a taste of their cracker. These first acts of symbolic thinking represent a major cognitive leap. Provide simple props: a play phone, a doll with a bottle, a toy set of keys. Model pretend play during the day: "Your bear looks hungry. Let\'s give him some pretend soup." Do not be surprised if your baby mostly watches you at first and then imitates days or weeks later.', source: 'DEVELOPMENT' as ContentSource, tags: ['pretend play', 'imagination', 'symbolic thinking', 'cognitive development', '12 months'] },
    { stageKey: 'born_month_12', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 87, title: 'The One-Year Milestone: Celebrating Yourself Too', summary: 'Your baby\'s first birthday is about more than cake. Honoring yourself as the parent who made it through year one.', content: 'A first birthday party is often planned with the baby as the focus, but this milestone is also about you. You have navigated sleepless nights, feeding challenges, developmental worries, identity shifts, and more love and fear than you knew you could feel. Consider marking the occasion in a way that honors your journey: a special dinner with your partner or a supportive friend, writing a letter to your one-year-ago self, or booking a massage or an afternoon of quiet. Modeling self-care and self-honoring is a gift to your child, too.', source: 'DEVELOPMENT' as ContentSource, tags: ['first birthday', 'parent milestone', 'self-care', 'celebration', '12 months'] },
    { stageKey: 'born_month_12', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 92, title: 'Walking: Typical Timeline and Red Flags', summary: 'By 12 months, about half of babies are taking independent steps. Understanding the wide normal range and when to seek evaluation.', content: 'The average age for first independent steps is around 12 months, but the normal range extends from 9 to 18 months. Babies who crawled early may not walk early; there is little correlation between the two. Late walking is often familial; if both parents walked late, your baby may too. Red flags that warrant evaluation: not pulling to stand by 12 months, not walking by 18 months, or any asymmetry in movement such as consistently dragging one leg or using only one side of the body. Early intervention for motor delays is highly effective, so trust your instincts and raise concerns early.', source: 'CLINICAL' as ContentSource, tags: ['walking', 'first steps', 'motor development', 'milestone', '12 months'] },
    { stageKey: 'born_month_12', category: 'DEVELOPMENT' as AdviceCategory, priority: 87, title: 'Emotional Development: The Full Range of Feelings', summary: 'By 12 months, your baby experiences a wide range of emotions but lacks the ability to regulate them. Your role as their calm anchor.', content: 'At 12 months, your baby can feel joy, anger, fear, affection, frustration, and excitement, but they have no ability to regulate these powerful feelings. Their tantrums and meltdowns are not manipulative; they are a nervous system overwhelmed by an emotion they cannot yet manage. Your calm presence during these storms literally co-regulates their nervous system. Name the feeling simply: "You are so frustrated that the block tower fell." Hold the boundary with kindness. Over time and hundreds of repetitions, your baby internalizes your regulation and begins to develop their own self-regulation skills.', source: 'DEVELOPMENT' as ContentSource, tags: ['emotional development', 'self-regulation', 'tantrums', 'co-regulation', '12 months'] },
    { stageKey: 'born_month_12', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 82, title: 'Push Toys and Riding Toys for New Walkers', summary: 'The right push toys support walking, balance, and confidence. Choosing safe options and using them well.', content: 'A sturdy push toy or walker wagon gives a new or nearly-walking baby motivation and support for practicing steps. Choose a push toy with a wide base, weighted for stability, with wheels that have adjustable resistance to prevent it from rolling too fast. Avoid sit-in baby walkers with wheels, which are associated with thousands of injuries annually and are banned in several countries. Push toys are best used on carpet initially, which provides natural resistance and softer falls. Supervise closely and clear a wide path.', source: 'DEVELOPMENT' as ContentSource, tags: ['push toys', 'walking', 'balance', 'safety', '12 months'] },
    { stageKey: 'born_month_12', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 85, title: 'Identity Beyond Parenthood: Reclaiming Pieces of Yourself', summary: 'A year into parenting, you may feel ready to reconnect with parts of yourself that have been on hold.', content: 'The first year often demands total immersion in the parent role, and many parents feel a loss of their pre-baby identity. As your baby becomes more independent, small reclamations become possible: a hobby for 30 minutes on a weekend, a professional development course, a regular exercise class, or simply reading a book that is not about parenting. These are not selfish acts; they are acts of wholeness that model a full, engaged life for your child. Reconnecting with yourself can also ease the transition from the infant year into toddlerhood, which requires a different kind of parenting energy.', source: 'DEVELOPMENT' as ContentSource, tags: ['identity', 'parent wellbeing', 'self-care', 'personal growth', '12 months'] },
  ];
  for (const card of cards) {
    await prisma.expertAdviceCard.upsert({
      where: { id: `seed_advice_${card.stageKey}_${card.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30)}` },
      update: card, create: { id: `seed_advice_${card.stageKey}_${card.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30)}`, ...card },
    });
  }
  console.log(`Seeded ${cards.length} infant advice cards (months 1-12)`);
}
